eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   teamMembers: () => (/* binding */ teamMembers)\n/* harmony export */ });\nconst teamMembers = [\n    {\n        name: \"Kim Todana\",\n        role: \"CEO\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Kim.webp\",\n        alt: \"Kim Todana\",\n        bio: \"Daughter of the late Hideo Todana founder of the Todana brand, Kim leads the company with a vision rooted in Japanese aesthetics and modern craftsmanship. She guides the studio’s global strategy, ensuring every collection reflects the values of purity, longevity, and thoughtful design. Under her leadership, Todana has grown into a benchmark for contemporary furniture that balances sculptural elegance with everyday function.\"\n    },\n    {\n        name: \"Cassie Williams\",\n        role: \"Creative Director & Furniture Designer\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/brooke.webp\",\n        alt: \"Cassie Williams\",\n        bio: \"Cassie shapes the artistic language of Todana through a blend of contemporary aesthetics and functional clarity. With a refined background in furniture and spatial design, she creates pieces defined by clean geometry, tactile materials, and timeless elegance. Her vision guides the studio’s collections, ensuring every object embodies balance, character, and purposeful simplicity.\"\n    },\n    {\n        name: \"Sung Yeon\",\n        role: \"Product Designer & Visual Artist\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Sung.webp\",\n        alt: \"Sung Yeon\",\n        bio: \"Sung blends artistic sensitivity with precise product design to shape pieces that feel both expressive and serene. Drawing inspiration from Korean and Japanese design principles, his work emphasizes balanced proportions, thoughtful material selection, and visual harmony. He contributes to Todana’s signature aesthetic by transforming subtle ideas into refined, tangible forms.\"\n    },\n    {\n        name: \"Shauna Johnson\",\n        role: \"Architect & Spatial Designer\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Shauna.webp\",\n        alt: \"Shauna Johnson\",\n        bio: \"Shauna crafts architectural environments that elevate Todana’s furniture through light, proportion, and spatial rhythm. With a background in contemporary architecture, she designs interiors that feel intentional, calm, and deeply connected to their materials. Her work enhances the experience of each piece, creating settings that highlight their sculptural qualities and functional grace.\"\n    },\n    {\n        name: \"Prince Khaled\",\n        role: \"Photographer & Visual Storyteller\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Prince.webp\",\n        alt: \"Prince Khaled\",\n        bio: \"Prince reveals the essence of Todana’s creations through a mastery of light, texture, and atmosphere. His photography transforms each piece into a visual narrative, highlighting the subtle details, materials, and sculptural forms that define the collection. With a refined, cinematic eye, he captures the quiet elegance at the heart of the brand.\"\n    },\n    {\n        name: \"Julian Fumbwa\",\n        role: \"Operations & Production Manager\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Julian.webp\",\n        alt: \"Julian Fumbwa\",\n        bio: \"Julian coordinates artisans, workshops, and production partners to ensure flawless execution across every collection. His meticulous approach guarantees that each piece reflects Todana’s commitment to precision, durability, and exceptional craftsmanship. And yeah he can also speak Swahili AND French.\"\n    },\n    {\n        name: \"Aya Mackenzie\",\n        role: \"Material Specialist & Craft Researcher\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/Aya.jpg\",\n        alt: \"Aya Mackenzie\",\n        bio: \"Aya explores woods, metals, stones, and textiles from across the globe, selecting materials not only for their beauty but for their longevity. Her research defines the tactile identity of Todana, ensuring each piece carries a sense of authenticity and refined texture.\"\n    },\n    {\n        name: \"John Moriyama\",\n        role: \"Chief Executive Officer\",\n        icon: \"/assets/icons/wheel_white.svg\",\n        photo: \"/assets/images/team/John.jpg\",\n        alt: \"John Moriyama\",\n        bio: \"John guides Todana’s global strategy with a vision rooted in design excellence and cultural heritage. With a strong background in luxury furniture and architectural brands, he ensures that every decision upholds the studio’s values of purity, craftsmanship, and timeless design.\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/team.ts\n");

